/**
 * MedX select runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Manages searchable dropdown state for warehouses, suppliers, and product categories.
 */
const SUPPLY_CHAIN_OPTIONS = Object.freeze({
  warehouses: [
    { value: "wh-east", label: "East Distribution Center", region: "US-EAST" },
    { value: "wh-west", label: "West Cold Storage", region: "US-WEST" },
    { value: "wh-central", label: "Central Hub", region: "US-CENTRAL" },
    { value: "wh-apac", label: "APAC Fulfillment", region: "APAC" },
  ],
  suppliers: [
    { value: "sup-pharma-a", label: "PharmaCorp International", tier: "A" },
    { value: "sup-pharma-b", label: "MedSupply Global", tier: "B" },
    { value: "sup-device-c", label: "DeviceWorks Ltd", tier: "A" },
    { value: "sup-generic-d", label: "Generic Essentials Co", tier: "C" },
  ],
  categories: [
    { value: "cat-vaccine", label: "Vaccines", coldChain: true },
    { value: "cat-antibiotic", label: "Antibiotics", coldChain: false },
    { value: "cat-device", label: "Medical Devices", coldChain: false },
    { value: "cat-consumable", label: "Consumables", coldChain: false },
  ],
});

const selectRegistry = new Map();

function buildSelectGroups(groupKey) {
  const options = SUPPLY_CHAIN_OPTIONS[groupKey];
  if (!options) return [];
  return options.map((opt) => ({
    ...opt,
    group: groupKey,
    searchableText: `${opt.label} ${opt.value}`.toLowerCase(),
  }));
}

function filterSelectOptions(groupKey, query) {
  const normalized = String(query ?? "").trim().toLowerCase();
  const all = buildSelectGroups(groupKey);
  if (!normalized) return all;
  return all.filter((opt) => opt.searchableText.includes(normalized));
}

function createSelect(config) {
  const id = config.id ?? `medx-select-${selectRegistry.size + 1}`;
  const entry = {
    id,
    groupKey: config.groupKey,
    value: config.value ?? null,
    placeholder: config.placeholder ?? "Select an option",
    disabled: Boolean(config.disabled),
    multiple: Boolean(config.multiple),
    open: false,
    highlightedIndex: -1,
    filterQuery: "",
    options: buildSelectGroups(config.groupKey),
    onSelect: typeof config.onSelect === "function" ? config.onSelect : null,
  };
  selectRegistry.set(id, entry);
  return entry;
}

function setSelectValue(id, value) {
  const entry = selectRegistry.get(id);
  if (!entry) return false;
  const option = entry.options.find((o) => o.value === value);
  if (!option) return false;
  entry.value = value;
  entry.open = false;
  entry.highlightedIndex = entry.options.indexOf(option);
  if (entry.onSelect) entry.onSelect(option);
  return true;
}

function navigateSelect(id, direction) {
  const entry = selectRegistry.get(id);
  if (!entry || !entry.open) return;
  const filtered = filterSelectOptions(entry.groupKey, entry.filterQuery);
  if (filtered.length === 0) return;
  const delta = direction === "up" ? -1 : 1;
  let next = entry.highlightedIndex + delta;
  if (next < 0) next = filtered.length - 1;
  if (next >= filtered.length) next = 0;
  entry.highlightedIndex = next;
}

function getSelectSnapshot(id) {
  const entry = selectRegistry.get(id);
  if (!entry) return null;
  const selected = entry.options.find((o) => o.value === entry.value);
  return {
    id: entry.id,
    groupKey: entry.groupKey,
    value: entry.value,
    label: selected?.label ?? entry.placeholder,
    optionCount: entry.options.length,
    filteredCount: filterSelectOptions(entry.groupKey, entry.filterQuery).length,
    open: entry.open,
  };
}

async function runMedxSelect() {
  console.log("[medx:ui:select] runtime initialized");
  console.log(`[medx:ui:select] optionGroups=${Object.keys(SUPPLY_CHAIN_OPTIONS).length}`);

  const warehouseSelect = createSelect({
    groupKey: "warehouses",
    placeholder: "Choose warehouse",
    value: "wh-east",
  });
  const supplierSelect = createSelect({
    groupKey: "suppliers",
    placeholder: "Choose supplier",
  });
  const categorySelect = createSelect({
    groupKey: "categories",
    placeholder: "Product category",
    value: "cat-vaccine",
  });

  supplierSelect.open = true;
  supplierSelect.filterQuery = "pharma";
  navigateSelect(supplierSelect.id, "down");
  setSelectValue(supplierSelect.id, "sup-pharma-a");

  const snapshots = [warehouseSelect, supplierSelect, categorySelect].map((s) =>
    getSelectSnapshot(s.id),
  );
  console.log(`[medx:ui:select] activeSelects=${selectRegistry.size}`);
  console.log("[medx:ui:select] snapshots", JSON.stringify(snapshots, null, 0));
  console.log("[medx:ui:select] bootstrap complete");
}

module.exports = runMedxSelect;
